  ('aboriginal-7fec267e-moex-00354', 'aboriginal-7fec267e', 'aboriginal-7fec267e-moex-111-3082b5f1', 'sub-aboriginal-7fec267e-04', NULL, 'single_choice', '國防部進行戰機起降演習，因巨大聲響造成鄰近鴨農養殖之鴨子大量死亡，鴨農得請求下列何項 救濟？', '["國防部飛行員因過失而未降低戰機起降時之噪音，飛行員應負國家賠償責任", "國防部因已設置噪音隔離設施，國防部不負任何填補責任", "鴨農所受之財產損失乃因公益而受特別犧牲，國防部應負損失補償責任", "此不屬於國家賠償法規範之範圍，人民應依民法請求國防部賠償其損害"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:02+00:00", "source_pdf_sha1": "30267b12713c", "answer_pdf_sha1": "0d471d4816b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "501", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般行政"}'::jsonb, NULL),
  ('aboriginal-7fec267e-moex-00355', 'aboriginal-7fec267e', 'aboriginal-7fec267e-moex-111-3082b5f1', 'sub-aboriginal-7fec267e-04', NULL, 'single_choice', '下列何種事故不構成國家賠償？', '["用路人騎車不慎碾壓因3天前下雨導致路面坑洞而受傷", "主管機關未善盡管理責任，任由無執照、無救生設施船舶載客，致乘客傷亡", "發布颱風警報後，海灘已用圍籬阻隔，海巡人員並當面警告遊客禁止進入，衝浪好手甲仍不顧 一切衝進海中後溺斃", "公務員未善盡地下公共管線維護管理義務，造成多處道路氣爆，致多人傷亡"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:02+00:00", "source_pdf_sha1": "30267b12713c", "answer_pdf_sha1": "0d471d4816b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "501", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般行政"}'::jsonb, NULL),
